<template>
  <div>
    <!-- <header-comp /> -->

    <section>
      <div class="title-mod">
          <br>
          <h2>Postales</h2>
          <v-divider class="mt-6 mx-4"></v-divider>
      </div>
      <br>
      <div>
        <section class="container_section">
          <v-row align="center" justify="center">
            <!-- Muestra las imágenes -->
            <!--<v-col v-for="(image, index) in paginatedImages" :key="index" cols="12" sm="4" md="3">-->
            <v-col v-for="(item, index) in paginatedImages" :key="index" cols="auto" class="p-2">
              <v-card class="card_postal" elevation="15">
                <img :src="item.img" alt="image" class="" loading="lazy">
                <div class="card_postal_content">
                  <p class="card_postal_title">{{item.title}}</p>
                  <p class="card_postal_desc">
                      {{item.description}}
                  </p>
                  <div class="card_postal_btn">
                      <v-btn @click="expandFile({type:'img', src:item.img})" elevation="5" color="#66666B" class="ma-0 white--text" small> ver postal</v-btn>
                  </div>
                </div>
              </v-card>
            </v-col>
          </v-row>
        </section>
        <!-- Paginación -->
        <br><br>
        <v-pagination v-model="currentPage" :length="pageCount" @input="updateUrl"></v-pagination>
      </div>
      <br>
    </section>

    <!-- <footer-comp /> -->
  </div>
</template>

<script>
// import HeaderComp from '@/components/20192024/HeaderComp.vue'
// import FooterComp from '@/components/20192024/FooterComp.vue'
import { mapActions } from 'vuex'

export default {
  name: 'HomeView',
  components: {
    // HeaderComp,
    // FooterComp
  },
  data () {
    return {
      itemsPerPage: 8,
      currentPage: 1,
      postcards: []
    }
  },
  computed: {
    paginatedImages () {
      const start = (this.currentPage - 1) * this.itemsPerPage
      return this.postcards.slice(start, start + this.itemsPerPage)
    },
    pageCount () {
      return Math.ceil(this.postcards.length / this.itemsPerPage)
    }
  },
  methods: {
    ...mapActions('S20192024', [
      'expandFile',
      'loadData'
    ]),
    updateUrl (page) {
      this.currentPage = page
      const url = new URL(window.location)
      url.searchParams.set('page', page)
      window.history.pushState({}, '', url)
    }
  },
  async created () {
    document.title = 'postales | Sistema de Información y Estadística sobre los Pueblos y Comunidades Indígenas'

    this.postcards = await this.loadData('20192024/json/postcards.json')
    const urlParams = new URLSearchParams(window.location.search)
    const page = parseInt(urlParams.get('page')) || 1
    this.currentPage = page
  }
}
</script>
